-- FIX: Duplicate Keys — keep only the first occurrence of each customer_id
CREATE OR REPLACE TABLE customers_deduped AS
WITH ranked AS (
    SELECT *,
           ROW_NUMBER() OVER (PARTITION BY customer_id) AS rn
    FROM read_csv_auto('data/raw/customers_raw.csv')
)
SELECT * EXCLUDE (rn)
FROM ranked
WHERE rn = 1;

-- Affected customer_ids (sample): ['C200574', 'C200371', 'C200526', 'C200566', 'C200336']

-- FIX: country — normalise to ISO 2-letter codes
UPDATE customers_clean
SET country = CASE
        WHEN LOWER(TRIM(country)) = 'uk ' THEN 'UK'
        WHEN LOWER(TRIM(country)) = 'u.k.' THEN 'UK'
        WHEN LOWER(TRIM(country)) = 'united states' THEN 'US'
        WHEN LOWER(TRIM(country)) = 'usa' THEN 'US'
        WHEN LOWER(TRIM(country)) = 'india' THEN 'IN'
        WHEN LOWER(TRIM(country)) = 'in ' THEN 'IN'
        WHEN LOWER(TRIM(country)) = 'in' THEN 'IN'
        WHEN LOWER(TRIM(country)) = 'ae' THEN 'AE'
        WHEN LOWER(TRIM(country)) = 'sg' THEN 'SG'
        ELSE UPPER(TRIM(country))
    END
WHERE LOWER(TRIM(country)) NOT IN ('in','uk','us','ae','sg');

-- FIX: segment — normalise to lowercase standard values
UPDATE customers_clean
SET segment = CASE
        WHEN LOWER(TRIM(segment)) = 'premium' THEN 'premium'
        WHEN LOWER(TRIM(segment)) = 'primium' THEN 'premium'
        WHEN LOWER(TRIM(segment)) = 'enterprise' THEN 'enterprise'
        WHEN LOWER(TRIM(segment)) = 'enterprize' THEN 'enterprise'
        WHEN LOWER(TRIM(segment)) = 'retail' THEN 'retail'
        ELSE LOWER(TRIM(segment))
    END
WHERE LOWER(TRIM(segment)) NOT IN ('retail','premium','enterprise');

-- FIX: is_active — normalise to true/false
UPDATE customers_clean
SET is_active = CASE
        WHEN LOWER(TRIM(is_active)) IN ('y','yes','1','true')  THEN 'true'
        WHEN LOWER(TRIM(is_active)) IN ('n','no','0','false')  THEN 'false'
        ELSE is_active
    END
WHERE LOWER(TRIM(is_active)) NOT IN ('true','false');

-- FIX: phone — add +91- prefix to bare 10-digit numbers
UPDATE customers_clean
SET phone = '+91-' || phone
WHERE phone NOT LIKE '+91-%'
  AND LENGTH(phone) = 10
  AND phone ~ '^[0-9]{10}$';

-- FIX: email — flag invalid emails (cannot auto-fix)
-- Review and correct manually or delete:
SELECT customer_id, email
FROM customers_clean
WHERE email NOT LIKE '%@%.%'
   OR email IS NULL;

-- FIX: signup_date — cast to DATE type; NULL out unparseable values
CREATE OR REPLACE TABLE customers_clean AS
SELECT * REPLACE (
    TRY_CAST(signup_date AS DATE) AS signup_date
)
FROM customers_clean;

-- FIX: is_active — already handled by out-of-domain fix above.
-- After normalising to 'true'/'false' strings, cast to BOOLEAN:
CREATE OR REPLACE TABLE customers_clean AS
SELECT * REPLACE (
    CAST(is_active AS BOOLEAN) AS is_active
)
FROM customers_clean;


-- STEP FINAL: Verify the cleaned table
SELECT COUNT(*) AS total_rows,
       COUNT(DISTINCT customer_id) AS unique_customers
FROM customers_clean;